// GEOPERF — Consolidation cross-LLM (port JS de consolidate.py)
// Reçoit 4 items en input (Perplexity, GPT, Gemini, Claude). Chacun = sortie chainLlm avec .text.

const LEGAL = ['inc','incorporated','corp','corporation','company','co','ltd','limited','llc','sa','sas','sarl','ag','gmbh','plc','spa','bv','nv','group','holding','holdings','international','global'];

const normalize = (s) => {
  if (!s) return '';
  let n = s.normalize('NFKD').replace(/[\u0300-\u036f]/g, '').toLowerCase();
  n = n.replace(/[^\w\s\-&]/g, ' ').replace(/\s+/g, ' ').trim();
  const tokens = n.split(' ');
  while (tokens.length && LEGAL.includes(tokens[tokens.length - 1].replace(/\.$/,''))) tokens.pop();
  return tokens.join(' ');
};

const rootDomain = (d) => {
  if (!d) return '';
  let dom = d.toLowerCase().trim().replace(/^https?:\/\//,'').replace(/^www\./,'').split('/')[0].split('?')[0];
  const parts = dom.split('.');
  return parts.length >= 2 ? parts.slice(-2).join('.') : dom;
};

// Clé de dédoublonnage : on PRIVILÉGIE le nom normalisé (résout le cas Goldman Sachs AM
// avec domaines gsam.com vs goldmansachs.com vs gsam.com/etfs). Le domaine reste
// collecté en métadonnée et sert au choix du canonicalDomain en sortie.
const matchKey = (name, domain) => {
  const n = normalize(name);
  if (n) return 'n:' + n;
  const d = rootDomain(domain);
  return d ? 'd:' + d : '';
};

// Extraction sécurisée du JSON depuis la réponse LLM
const parseLLM = (text) => {
  if (!text) return null;
  try { return JSON.parse(text); } catch (e) {}
  // Tentative : extraire le premier { ... } équilibré
  const m = text.match(/\{[\s\S]*\}/);
  if (m) { try { return JSON.parse(m[0]); } catch (e) {} }
  return null;
};

const providers = ['perplexity', 'openai', 'google', 'anthropic'];
const llmOutputs = {};
for (let i = 0; i < items.length && i < 4; i++) {
  const txt = items[i]?.json?.text;
  llmOutputs[providers[i]] = parseLLM(txt) || { companies: [] };
}

const byKey = new Map();
for (const provider of providers) {
  const payload = llmOutputs[provider];
  for (const c of (payload?.companies || [])) {
    const key = matchKey(c.name, c.domain);
    if (!key) continue;
    if (!byKey.has(key)) byKey.set(key, { names_seen: [], domains_seen: [], countries: [], cities: [], employees_ranges: [], descriptions: [], key_metrics: [], cited_by: {}, ranks_per_llm: {}, confidence_per_llm: {}, sources: [] });
    const e = byKey.get(key);
    e.names_seen.push(c.name);
    if (c.domain) e.domains_seen.push(rootDomain(c.domain));
    if (c.country) e.countries.push(c.country);
    if (c.city) e.cities.push(c.city);
    if (c.employees_range) e.employees_ranges.push(c.employees_range);
    if (c.description) e.descriptions.push([provider, c.description]);
    if (c.key_metric) e.key_metrics.push([provider, c.key_metric]);
    e.cited_by[provider] = true;
    if (c.rank != null) e.ranks_per_llm[provider] = c.rank;
    if (c.confidence) e.confidence_per_llm[provider] = c.confidence;
    for (const s of (c.sources || [])) if (s?.url) e.sources.push({ ...s, from_llm: provider });
  }
}

const priority = ['perplexity', 'openai', 'anthropic', 'google'];
const consolidated = [];
for (const [key, e] of byKey) {
  const counts = {};
  for (const n of e.names_seen) counts[n] = (counts[n] || 0) + 1;
  const canonicalName = Object.entries(counts).sort((a,b) => b[1] - a[1])[0][0];
  let canonicalDomain = '';
  if (e.domains_seen.length) {
    const dc = {};
    for (const d of e.domains_seen) dc[d] = (dc[d] || 0) + 1;
    canonicalDomain = Object.entries(dc).sort((a,b) => b[1] - a[1])[0][0];
  }
  let bestDesc = '';
  for (const p of priority) { for (const [src, d] of e.descriptions) if (src === p) { bestDesc = d; break; } if (bestDesc) break; }
  let bestMetric = null;
  for (const p of priority) { for (const [src, m] of e.key_metrics) if (src === p && m) { bestMetric = m; break; } if (bestMetric) break; }
  const citedFull = {};
  for (const p of providers) citedFull[p] = !!e.cited_by[p];
  const visScore = Object.values(citedFull).filter(Boolean).length;
  const ranks = Object.values(e.ranks_per_llm).filter(r => r != null);
  const avgPos = ranks.length ? Math.round(ranks.reduce((a,b)=>a+b,0)/ranks.length * 100) / 100 : null;
  const sourceUrls = new Set(e.sources.map(s => s.url).filter(Boolean));
  consolidated.push({
    name: canonicalName,
    name_normalized: normalize(canonicalName),
    domain: canonicalDomain,
    country: e.countries[0] || null,
    city: e.cities[0] || null,
    employees_range: e.employees_ranges[0] || null,
    best_description: bestDesc,
    key_metric: bestMetric,
    cited_by: citedFull,
    visibility_score: visScore,
    ranks_per_llm: e.ranks_per_llm,
    avg_position: avgPos,
    source_count: sourceUrls.size,
    sources: e.sources,
    confidence_per_llm: e.confidence_per_llm,
  });
}
consolidated.sort((a, b) => (b.visibility_score - a.visibility_score) || ((a.avg_position ?? 999) - (b.avg_position ?? 999)));
consolidated.forEach((c, i) => c.rank_consolidated = i + 1);

const stats = { total_unique_companies: consolidated.length, cited_by_4_llms: 0, cited_by_3_llms: 0, cited_by_2_llms: 0, cited_by_1_llm: 0 };
for (const c of consolidated) stats['cited_by_' + c.visibility_score + '_llms'] = (stats['cited_by_' + c.visibility_score + '_llms'] || 0) + 1;

const ctx = $('Prepare context').item.json;

// Output : un seul item avec tout le payload + les raw_responses prêts pour insertion
return [{
  json: {
    report_id: ctx.report_id,
    sous_categorie: ctx.sous_categorie,
    year: ctx.year,
    consolidated: { report_id: ctx.report_id, category: ctx.sous_categorie, year: ctx.year, providers_used: providers, companies: consolidated, stats: stats },
    raw_responses: providers.map((p, i) => ({
      report_id: ctx.report_id,
      provider: p,
      model: ['perplexity/sonar-pro','openai/gpt-4o-search-preview','google/gemini-2.5-pro','anthropic/claude-sonnet-4.6'][i],
      prompt: '(stored in workflow logs)',
      response_json: llmOutputs[p],
      sources_json: (llmOutputs[p]?.companies || []).flatMap(c => c.sources || [])
    }))
  }
}];
